#include<bits/stdc++.h>
using namespace std;
double a,b,c;

bool pan(double i){
    double x=0;
        double mu=(1+i/100);
        for(int j=1;j<=c;j++){
            x+=(b/mu);
            mu*=(1+i/100);
        }
        if(x-a<0){
            return 1;
        }else{
            return 0;
        }
}
int main(){
    cin>>a>>b>>c;
     double l=0.01,r=300,ans=0;
    while(l<r){
        //cout<<l<<' '<<r<<"\n";
        double mid=(l+r)/2;
        if(pan(mid)){
            ans=mid;
            r=mid-0.01;
        }else{
            l=mid+0.01;
        }
    }
    ans=ans-0.01;
    ans=round(ans*10)/10;
    printf("%.1lf",ans);
    return 0;
}
